    start_date timestamp without time zone NOT NULL,
    end_date timestamp without time zone NOT NULL,
    renewal_date timestamp without time zone NOT NULL,
    credentials_encrypted text,
    status character varying(20) DEFAULT 'active'::character varying NOT NULL,
    metadata jsonb,
    created_at timestamp without time zone DEFAULT now(),
    order_id uuid,
    product_variant_id uuid,
    price_cents integer,
    currency character varying(10),
    auto_renew boolean,
    next_billing_at timestamp without time zone,
    renewal_method character varying(20),
    status_reason text,
    referral_reward_id uuid,
    pre_launch_reward_id uuid,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    billing_payment_method_id uuid,
    auto_renew_enabled_at timestamp without time zone,
    auto_renew_disabled_at timestamp without time zone,
    term_months integer,
    base_price_cents integer,
    discount_percent numeric(5,2),
    term_start_at timestamp without time zone,
    cancellation_requested_at timestamp without time zone,
    cancellation_reason text,
    renewal_invoice_payment_id uuid,
    renewal_invoice_status character varying(30),
    order_item_id uuid,
    delivered_at timestamp without time zone,
    delivered_by uuid,
    delivery_email_sent_at timestamp without time zone,
    activation_handshake_state character varying(40) DEFAULT 'none'::character varying NOT NULL,
    activation_instructions_delivered_at timestamp without time zone,
    activation_customer_ready_at timestamp without time zone,
    activation_link_delivered_at timestamp without time zone,
    activation_handshake_restarted_at timestamp without time zone,
    CONSTRAINT subscriptions_activation_handshake_state_check CHECK (((activation_handshake_state)::text = ANY ((ARRAY['none'::character varying, 'instructions_delivered'::character varying, 'awaiting_customer'::character varying, 'customer_ready'::character varying, 'link_delivered'::character varying])::text[]))),
    CONSTRAINT subscriptions_base_price_cents_check CHECK ((base_price_cents >= 0)),
    CONSTRAINT subscriptions_date_order_check CHECK ((start_date <= end_date)),
    CONSTRAINT subscriptions_discount_percent_check CHECK (((discount_percent >= (0)::numeric) AND (discount_percent <= (100)::numeric))),
    CONSTRAINT subscriptions_renewal_check CHECK ((renewal_date >= start_date)),
    CONSTRAINT subscriptions_status_check CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'expired'::character varying, 'cancelled'::character varying, 'pending'::character varying])::text[]))),
    CONSTRAINT subscriptions_term_months_check CHECK ((term_months > 0))
);


